sql:
SELECT AVG(v.battery_capacity) AS avg_battery_capacity
FROM vehicles v
WHERE (SELECT COUNT(*) FROM sensors s WHERE s.vehicle_id = v.vehicle_id) > 1;

external_knowledge:
- 'Earliest' and 'latest' refer to the timestamps of data_id 1 and 0, respectively; 
- The 'time period' is the range between these two timestamps; 
- 'Active' means the sensor has recorded at least one data point within the specified time range.

sql:
SELECT sensors.sensor_type, COUNT(DISTINCT sensors.sensor_id) as sensor_count
FROM sensors
INNER JOIN sensor_data ON sensors.sensor_id = sensor_data.sensor_id
WHERE sensor_data.ts >= (
  SELECT ts FROM sensor_data WHERE data_id = 0
) AND sensor_data.ts <= (
  SELECT ts FROM sensor_data WHERE data_id = 1
)
GROUP BY sensors.sensor_type;

SELECT vehicles.vehicle_id, vehicles.vin, vehicles.make, vehicles.model, vehicles.year, vehicles.engine_type, vehicle_config.config
FROM vehicles
JOIN vehicle_config ON vehicles.vehicle_id = vehicle_config.vehicle_id;

SELECT * FROM weather 
ORDER BY timestamp DESC 
LIMIT 1;

SELECT *
FROM vehicles
WHERE vehicle_id IN (SELECT vehicle_id FROM alerts);

SELECT AVG(maintenance_count)
FROM (
  SELECT vehicle_id, COUNT(maintenance_id) AS maintenance_count
  FROM maintenance
  GROUP BY vehicle_id
);
